moduleLoaders["SyntaxToken"] = function()
    local script = { Parent = scriptParent }
    -- Auto-generated by SimpleEmitter

    local _SyntaxKind
    local SyntaxKind = setmetatable({}, {__index = function(_, k)
    	if not _SyntaxKind then _SyntaxKind = require(script.Parent.SyntaxKind) end
    	return _SyntaxKind.SyntaxKind[k]
    end})

    type TokenInfo_self = {
    	Kind: SyntaxKind;
    	Text: string;
    	Start: number;
    	Length: number;
    }

    local TokenInfo = {}
    TokenInfo.__index = TokenInfo
    type TokenInfo = typeof(setmetatable({} :: TokenInfo_self, TokenInfo))

