    type SyntaxWalker_self = {
    	_depth: number;
    	Depth: number;
    }

    local SyntaxWalker = {}
    SyntaxWalker.__index = SyntaxWalker
    type SyntaxWalker = typeof(setmetatable({} :: SyntaxWalker_self, SyntaxWalker))

    function SyntaxWalker.new(): SyntaxWalker
    	local self = setmetatable({
    		_depth = 0,
    		Depth = 0,
    	} :: SyntaxWalker_self, SyntaxWalker)
    	self._depth = 0
    	return self
    end

    function SyntaxWalker.Visit(self: SyntaxWalker, node: SyntaxNode): ()
    	if node == nil then
    		return
    	end
    	node:AcceptWalker(self)
    end

    function SyntaxWalker.DefaultVisit(self: SyntaxWalker, node: SyntaxNode): ()
    end

    function SyntaxWalker.VisitCompilationUnit(self: SyntaxWalker, node: CompilationUnitSyntax): ()
    	for i = 0, #node.Members - 1 do
    		self._depth += 1
    		SyntaxWalker.Visit(self, node.Members[i + 1])
    		self._depth -= 1
    	end
    end

    function SyntaxWalker.VisitClassDeclaration(self: SyntaxWalker, node: ClassDeclarationSyntax): ()
    	for i = 0, #node.Members - 1 do
    		self._depth += 1
    		SyntaxWalker.Visit(self, node.Members[i + 1])
    		self._depth -= 1
    	end
    end

    function SyntaxWalker.VisitStructDeclaration(self: SyntaxWalker, node: StructDeclarationSyntax): ()
    	for i = 0, #node.Members - 1 do
    		self._depth += 1
    		SyntaxWalker.Visit(self, node.Members[i + 1])
    		self._depth -= 1
    	end
    end

    function SyntaxWalker.VisitEnumDeclaration(self: SyntaxWalker, node: EnumDeclarationSyntax): ()
    end

    function SyntaxWalker.VisitMethodDeclaration(self: SyntaxWalker, node: MethodDeclarationSyntax): ()
    	if node.Body ~= nil then
    		self._depth += 1
    		SyntaxWalker.Visit(self, node.Body)
    		self._depth -= 1
    	end
    end

    function SyntaxWalker.VisitConstructorDeclaration(self: SyntaxWalker, node: ConstructorDeclarationSyntax): ()
    	if node.InitializerArguments ~= nil then
    		for i = 0, #node.InitializerArguments - 1 do
    			self._depth += 1
    			SyntaxWalker.Visit(self, node.InitializerArguments[i + 1])
    			self._depth -= 1
    		end
    	end
    	if node.Body ~= nil then
    		self._depth += 1
    		SyntaxWalker.Visit(self, node.Body)
    		self._depth -= 1
    	end
    end

    function SyntaxWalker.VisitFieldDeclaration(self: SyntaxWalker, node: FieldDeclarationSyntax): ()
    	if node.Initializer ~= nil then
    		self._depth += 1
    		SyntaxWalker.Visit(self, node.Initializer)
    		self._depth -= 1
    	end
    end

    function SyntaxWalker.VisitPropertyDeclaration(self: SyntaxWalker, node: PropertyDeclarationSyntax): ()
    	if node.ExpressionBody ~= nil then
    		self._depth += 1
    		SyntaxWalker.Visit(self, node.ExpressionBody)
    		self._depth -= 1
    	end
    end

    function SyntaxWalker.VisitBlock(self: SyntaxWalker, node: BlockSyntax): ()
    	for i = 0, #node.Statements - 1 do
    		self._depth += 1
    		SyntaxWalker.Visit(self, node.Statements[i + 1])
    		self._depth -= 1
    	end
    end

    function SyntaxWalker.VisitReturnStatement(self: SyntaxWalker, node: ReturnStatementSyntax): ()
    	if node.Expression ~= nil then
    		self._depth += 1
    		SyntaxWalker.Visit(self, node.Expression)
    		self._depth -= 1
    	end
    end

    function SyntaxWalker.VisitIfStatement(self: SyntaxWalker, node: IfStatementSyntax): ()
    	self._depth += 1
    	SyntaxWalker.Visit(self, node.Condition)
    	self._depth -= 1
    	self._depth += 1
    	SyntaxWalker.Visit(self, node.ThenBody)
    	self._depth -= 1
    	if node.ElseBody ~= nil then
    		self._depth += 1
    		SyntaxWalker.Visit(self, node.ElseBody)
    		self._depth -= 1
    	end
    end

    function SyntaxWalker.VisitWhileStatement(self: SyntaxWalker, node: WhileStatementSyntax): ()
    	self._depth += 1
    	SyntaxWalker.Visit(self, node.Condition)
    	self._depth -= 1
    	self._depth += 1
    	SyntaxWalker.Visit(self, node.Body)
    	self._depth -= 1
    end

    function SyntaxWalker.VisitExpressionStatement(self: SyntaxWalker, node: ExpressionStatementSyntax): ()
    	self._depth += 1
    	SyntaxWalker.Visit(self, node.Expression)
    	self._depth -= 1
    end

    function SyntaxWalker.VisitLocalDeclaration(self: SyntaxWalker, node: LocalDeclarationStatementSyntax): ()
    	if node.Initializer ~= nil then
    		self._depth += 1
    		SyntaxWalker.Visit(self, node.Initializer)
    		self._depth -= 1
    	end
    end

    function SyntaxWalker.VisitForStatement(self: SyntaxWalker, node: ForStatementSyntax): ()
    	if node.Declaration ~= nil then
    		self._depth += 1
    		SyntaxWalker.Visit(self, node.Declaration)
    		self._depth -= 1
    	end
    	if node.Condition ~= nil then
    		self._depth += 1
    		SyntaxWalker.Visit(self, node.Condition)
    		self._depth -= 1
    	end
    	for i = 0, #node.Incrementors - 1 do
    		self._depth += 1
    		SyntaxWalker.Visit(self, node.Incrementors[i + 1])
    		self._depth -= 1
    	end
    	self._depth += 1
    	SyntaxWalker.Visit(self, node.Body)
    	self._depth -= 1
    end

    function SyntaxWalker.VisitForEachStatement(self: SyntaxWalker, node: ForEachStatementSyntax): ()
    	self._depth += 1
    	SyntaxWalker.Visit(self, node.Expression)
    	self._depth -= 1
    	self._depth += 1
    	SyntaxWalker.Visit(self, node.Body)
    	self._depth -= 1
    end

    function SyntaxWalker.VisitDoStatement(self: SyntaxWalker, node: DoStatementSyntax): ()
    	self._depth += 1
    	SyntaxWalker.Visit(self, node.Body)
    	self._depth -= 1
    	self._depth += 1
    	SyntaxWalker.Visit(self, node.Condition)
    	self._depth -= 1
    end

    function SyntaxWalker.VisitBreakStatement(self: SyntaxWalker, node: BreakStatementSyntax): ()
    	SyntaxWalker.DefaultVisit(self, node)
    end

    function SyntaxWalker.VisitContinueStatement(self: SyntaxWalker, node: ContinueStatementSyntax): ()
    	SyntaxWalker.DefaultVisit(self, node)
    end

    function SyntaxWalker.VisitSwitchStatement(self: SyntaxWalker, node: SwitchStatementSyntax): ()
    	self._depth += 1
    	SyntaxWalker.Visit(self, node.Expression)
    	self._depth -= 1
    	for i = 0, #node.Sections - 1 do
    		self._depth += 1
    		SyntaxWalker.Visit(self, node.Sections[i + 1])
    		self._depth -= 1
    	end
    end

    function SyntaxWalker.VisitSwitchSection(self: SyntaxWalker, node: SwitchSectionSyntax): ()
    	for i = 0, #node.Labels - 1 do
    		if node.Labels[i + 1] ~= nil then
    			self._depth += 1
    			SyntaxWalker.Visit(self, node.Labels[i + 1])
    			self._depth -= 1
    		end
    	end
    	for i = 0, #node.Statements - 1 do
    		self._depth += 1
    		SyntaxWalker.Visit(self, node.Statements[i + 1])
    		self._depth -= 1
    	end
    end

    function SyntaxWalker.VisitTryStatement(self: SyntaxWalker, node: TryStatementSyntax): ()
    	self._depth += 1
    	SyntaxWalker.Visit(self, node.Block)
    	self._depth -= 1
    	for i = 0, #node.Catches - 1 do
    		self._depth += 1
    		SyntaxWalker.Visit(self, node.Catches[i + 1])
    		self._depth -= 1
    	end
    	if node.FinallyBlock ~= nil then
    		self._depth += 1
    		SyntaxWalker.Visit(self, node.FinallyBlock)
    		self._depth -= 1
    	end
    end

    function SyntaxWalker.VisitCatchClause(self: SyntaxWalker, node: CatchClauseSyntax): ()
    	self._depth += 1
    	SyntaxWalker.Visit(self, node.Block)
    	self._depth -= 1
    end

    function SyntaxWalker.VisitThrowStatement(self: SyntaxWalker, node: ThrowStatementSyntax): ()
    	if node.Expression ~= nil then
    		self._depth += 1
    		SyntaxWalker.Visit(self, node.Expression)
    		self._depth -= 1
    	end
    end

    function SyntaxWalker.VisitLockStatement(self: SyntaxWalker, node: LockStatementSyntax): ()
    	self._depth += 1
    	SyntaxWalker.Visit(self, node.Expression)
    	SyntaxWalker.VisitBlock(self, node.Block)
    	self._depth -= 1
    end

    function SyntaxWalker.VisitUsingStatement(self: SyntaxWalker, node: UsingStatementSyntax): ()
    	self._depth += 1
    	if node.Declaration ~= nil then
    		SyntaxWalker.VisitLocalDeclaration(self, node.Declaration)
    	end
    	if node.Expression ~= nil then
    		SyntaxWalker.Visit(self, node.Expression)
    	end
    	SyntaxWalker.VisitBlock(self, node.Block)
    	self._depth -= 1
    end

    function SyntaxWalker.VisitTupleDeconstructionStatement(self: SyntaxWalker, node: TupleDeconstructionStatementSyntax): ()
    	self._depth += 1
    	if node.Initializer ~= nil then
    		SyntaxWalker.Visit(self, node.Initializer)
    	end
    	self._depth -= 1
    end

    function SyntaxWalker.VisitLiteralExpression(self: SyntaxWalker, node: LiteralExpressionSyntax): ()
    end

    function SyntaxWalker.VisitIdentifierName(self: SyntaxWalker, node: IdentifierNameSyntax): ()
    end

    function SyntaxWalker.VisitBinaryExpression(self: SyntaxWalker, node: BinaryExpressionSyntax): ()
    	self._depth += 1
    	SyntaxWalker.Visit(self, node.Left)
    	self._depth -= 1
    	self._depth += 1
    	SyntaxWalker.Visit(self, node.Right)
    	self._depth -= 1
    end

    function SyntaxWalker.VisitPrefixUnaryExpression(self: SyntaxWalker, node: PrefixUnaryExpressionSyntax): ()
    	self._depth += 1
    	SyntaxWalker.Visit(self, node.Operand)
    	self._depth -= 1
    end

    function SyntaxWalker.VisitParenthesizedExpression(self: SyntaxWalker, node: ParenthesizedExpressionSyntax): ()
