    			self._typeNames[self._typeCount + 1] = str.Name
    			self._typeCount += 1
    		elseif kind == 8856 then
    			local enm: EnumDeclarationSyntax = unit.Members[i + 1]
    			self._typeNames[self._typeCount + 1] = enm.Name
    			self._typeCount += 1
    		end
    	end
