    		SimpleEmitter.AppendLine(self, "")
    		local ret: string = "return { "
    		for i = 0, self._typeCount - 1 do
    			if i > 0 then
    				ret = ret .. ", "
    			end
    			ret = ret .. self._typeNames[i + 1] .. " = " .. self._typeNames[i + 1]
