    			elseif not atEnd and string.byte(inner, i + 1) == string.byte("<", 1) then
    				depth3 += 1
    			elseif not atEnd and string.byte(inner, i + 1) == string.byte(">", 1) then
    				depth3 -= 1
    			end
    		end
    		return "{ " .. mapped .. " }"
    	end
    	if #csharpType > 9 and string.sub(csharpType, 0 + 1, 0 + 9) == "Nullable<" and string.byte(csharpType, #csharpType - 1 + 1) == string.byte(">", 1) then
    		local inner: string = string.sub(csharpType, 9 + 1, 9 + #csharpType - 10)
    		return SimpleEmitter.MapType(self, inner) .. "?"
    	end
    	if csharpType == "TimeSpan" then
    		return "number"
    	end
    	if csharpType == "DateTime" then
    		return "number"
    	end
    	if csharpType == "Guid" then
    		return "string"
    	end
    	if csharpType == "Stopwatch" then
    		return "any"
    	end
    	if #csharpType > 5 and string.sub(csharpType, 0 + 1, 0 + 5) == "Span<" then
    		local spanInner: string = string.sub(csharpType, 5 + 1, 5 + #csharpType - 6)
    		if spanInner == "byte" then
    			return "buffer"
    		end
    		return "{ " .. SimpleEmitter.MapType(self, spanInner) .. " }"
    	end
    	if #csharpType > 13 and string.sub(csharpType, 0 + 1, 0 + 13) == "ReadOnlySpan<" then
    		local rosInner: string = string.sub(csharpType, 13 + 1, 13 + #csharpType - 14)
    		if rosInner == "byte" then
    			return "buffer"
    		end
    		return "{ " .. SimpleEmitter.MapType(self, rosInner) .. " }"
    	end
    	if #csharpType > 7 and string.sub(csharpType, 0 + 1, 0 + 7) == "Memory<" then
    		local memInner: string = string.sub(csharpType, 7 + 1, 7 + #csharpType - 8)
    		if memInner == "byte" then
    			return "buffer"
    		end
    		return "{ " .. SimpleEmitter.MapType(self, memInner) .. " }"
    	end
    	if csharpType == "Task" then
    		return "()"
    	end
    	if #csharpType > 5 and string.sub(csharpType, 0 + 1, 0 + 5) == "Task<" and string.byte(csharpType, #csharpType - 1 + 1) == string.byte(">", 1) then
    		local inner: string = string.sub(csharpType, 5 + 1, 5 + #csharpType - 6)
    		return SimpleEmitter.MapType(self, inner)
    	end
    	return csharpType
    end

    function SimpleEmitter.DefaultForType(self: SimpleEmitter, csharpType: string): string
    	if csharpType == nil then
    		return "nil"
    	end
    	if csharpType == "string" then
    		return "\"\""
    	end
    	if csharpType == "bool" then
    		return "false"
    	end
    	if csharpType == "StringBuilder" then
    		return "\"\""
    	end
    	if csharpType == "int" or csharpType == "float" or csharpType == "double" or csharpType == "long" or csharpType == "short" or csharpType == "byte" or csharpType == "sbyte" or csharpType == "ushort" or csharpType == "uint" or csharpType == "ulong" or csharpType == "decimal" or csharpType == "char" then
    		return "0"
    	end
    	if #csharpType > 2 and string.byte(csharpType, #csharpType - 1 + 1) == string.byte("]", 1) and string.byte(csharpType, #csharpType - 2 + 1) == string.byte("[", 1) then
    		return "{}"
    	end
    	if #csharpType > 5 and string.sub(csharpType, 0 + 1, 0 + 5) == "List<" then
    		return "{}"
    	end
    	if #csharpType > 11 and string.sub(csharpType, 0 + 1, 0 + 11) == "Dictionary<" then
    		return "{}"
    	end
    	if #csharpType > 8 and string.sub(csharpType, 0 + 1, 0 + 8) == "HashSet<" then
    		return "{}"
    	end
    	if #csharpType > 6 and string.sub(csharpType, 0 + 1, 0 + 6) == "Queue<" then
    		return "{}"
    	end
    	if #csharpType > 6 and string.sub(csharpType, 0 + 1, 0 + 6) == "Stack<" then
    		return "{}"
    	end
    	return "nil :: any"
    end

    function SimpleEmitter.VisitClassDeclaration(self: SimpleEmitter, node: ClassDeclarationSyntax): ()
    	SimpleEmitter.EmitClassOrStruct(self, node.Name, node.BaseTypeName, node.Members, false)
    end

    function SimpleEmitter.VisitStructDeclaration(self: SimpleEmitter, node: StructDeclarationSyntax): ()
    	SimpleEmitter.EmitClassOrStruct(self, node.Name, node.BaseTypeName, node.Members, true)
    end

    function SimpleEmitter.EmitClassOrStruct(self: SimpleEmitter, name: string, baseTypeName: string, members: { MemberDeclarationSyntax }, isStruct: boolean): ()
    	local savedClassName: string = self._currentClassName
    	local savedBaseClassName: string = self._baseClassName
    	self._currentClassName = name
    	self._baseClassName = baseTypeName
    	self._fieldCount = 0
    	self._staticFieldCount = 0
    	self._methodCount = 0
    	self._hasInstanceMembers = false
    	for i = 0, #members - 1 do
    		local kind: number = members[i + 1].Kind
    		if kind == 8873 then
    			local field: FieldDeclarationSyntax = members[i + 1]
    			if field.IsStatic then
    				self._staticFieldNames[self._staticFieldCount + 1] = field.Name
    				self._staticFieldTypes[self._staticFieldCount + 1] = field.TypeName
    				if field.Initializer ~= nil then
    					self._staticFieldDefaults[self._staticFieldCount + 1] = SimpleEmitter.EmitExpression(self, field.Initializer)
    				else
    					self._staticFieldDefaults[self._staticFieldCount + 1] = nil
    				end
    				self._staticFieldCount += 1
    			else
    				self._fieldNames[self._fieldCount + 1] = field.Name
    				self._fieldTypes[self._fieldCount + 1] = field.TypeName
    				if field.Initializer ~= nil then
    					self._fieldDefaults[self._fieldCount + 1] = SimpleEmitter.EmitExpression(self, field.Initializer)
    				else
    					self._fieldDefaults[self._fieldCount + 1] = nil
    				end
    				self._fieldCount += 1
    				self._hasInstanceMembers = true
    			end
    		elseif kind == 8892 then
    			local prop: PropertyDeclarationSyntax = members[i + 1]
    			if not prop.IsStatic and prop.HasGetter and prop.ExpressionBody == nil then
    				self._fieldNames[self._fieldCount + 1] = prop.Name
    				self._fieldTypes[self._fieldCount + 1] = prop.TypeName
    				self._fieldDefaults[self._fieldCount + 1] = nil
    				self._fieldCount += 1
    				self._hasInstanceMembers = true
    			elseif prop.IsStatic then
    				self._staticFieldNames[self._staticFieldCount + 1] = prop.Name
    				self._staticFieldTypes[self._staticFieldCount + 1] = prop.TypeName
    				self._staticFieldDefaults[self._staticFieldCount + 1] = nil
    				self._staticFieldCount += 1
    			end
    		elseif kind == 8875 then
    			local method: MethodDeclarationSyntax = members[i + 1]
    			if not method.IsStatic then
    				self._hasInstanceMembers = true
    			end
    			if self._methodCount < 128 then
    				self._methodNames[self._methodCount + 1] = method.Name
    				self._isMethodStatic[self._methodCount + 1] = method.IsStatic
    				self._methodCount += 1
    			end
    		elseif kind == 8878 then
    			self._hasInstanceMembers = true
    		end
    	end
    	local isAllStatic: boolean = not self._hasInstanceMembers and self._fieldCount == 0
    	if not isAllStatic and self._fieldCount > 0 then
    		SimpleEmitter.AppendLine(self, "type " .. name .. "_self = {")
    		SimpleEmitter.Indent(self)
    		for i = 0, self._fieldCount - 1 do
    			SimpleEmitter.AppendLine(self, self._fieldNames[i + 1] .. ": " .. SimpleEmitter.MapType(self, self._fieldTypes[i + 1]) .. ";")
    		end
    		SimpleEmitter.Dedent(self)
    		SimpleEmitter.AppendLine(self, "}")
    		SimpleEmitter.AppendLine(self, "")
    	end
    	if baseTypeName ~= nil then
    		SimpleEmitter.AppendLine(self, "local " .. name .. " = setmetatable({}, {__index = " .. baseTypeName .. "})")
    	else
    		SimpleEmitter.AppendLine(self, "local " .. name .. " = {}")
    	end
    	if not isAllStatic then
    		SimpleEmitter.AppendLine(self, name .. ".__index = " .. name)
    		SimpleEmitter.AppendLine(self, "export type " .. name .. " = typeof(setmetatable({} :: " .. name .. "_self, " .. name .. "))")
    	end
    	SimpleEmitter.AppendLine(self, "")
    	for i = 0, self._staticFieldCount - 1 do
    		local val: string = self._staticFieldDefaults[i + 1]
    		if val ~= nil then
    			SimpleEmitter.AppendLine(self, name .. "." .. self._staticFieldNames[i + 1] .. " = " .. val)
    		else
    			SimpleEmitter.AppendLine(self, name .. "." .. self._staticFieldNames[i + 1] .. " = " .. SimpleEmitter.DefaultForType(self, self._staticFieldTypes[i + 1]))
    		end
    	end
    	if self._staticFieldCount > 0 then
    		SimpleEmitter.AppendLine(self, "")
    	end
    	local hasCtor: boolean = false
    	for i = 0, #members - 1 do
    		if members[i + 1].Kind == 8878 then
    			local ctor: ConstructorDeclarationSyntax = members[i + 1]
    			SimpleEmitter.EmitConstructor(self, name, ctor)
    			SimpleEmitter.AppendLine(self, "")
    			hasCtor = true
    		end
    	end
    	if not hasCtor and not isAllStatic then
    		SimpleEmitter.EmitDefaultConstructor(self, name)
    		SimpleEmitter.AppendLine(self, "")
    	end
    	for i = 0, #members - 1 do
    		if members[i + 1].Kind == 8875 then
    			local method: MethodDeclarationSyntax = members[i + 1]
    			SimpleEmitter.EmitMethod(self, name, method, isAllStatic)
    			SimpleEmitter.AppendLine(self, "")
    		end
    	end
    	for i = 0, #members - 1 do
    		if members[i + 1].Kind == 8892 then
    			local prop: PropertyDeclarationSyntax = members[i + 1]
    			if prop.ExpressionBody ~= nil then
    				SimpleEmitter.EmitExpressionProperty(self, name, prop, isAllStatic)
    				SimpleEmitter.AppendLine(self, "")
    			end
    		end
    	end
    	self._currentClassName = savedClassName
    	self._baseClassName = savedBaseClassName
    end

    function SimpleEmitter.EmitDefaultConstructor(self: SimpleEmitter, className: string): ()
    	SimpleEmitter.AppendLine(self, "function " .. className .. ".new(): " .. className)
    	SimpleEmitter.Indent(self)
    	if self._baseClassName ~= nil then
    		SimpleEmitter.AppendLine(self, "local self = setmetatable(" .. self._baseClassName .. ".new() :: any, " .. className .. ")")
    		for i = 0, self._fieldCount - 1 do
    			local val: string = self._fieldDefaults[i + 1]
    			if val == nil then
    				val = SimpleEmitter.DefaultForType(self, self._fieldTypes[i + 1])
    			end
    			SimpleEmitter.AppendLine(self, "self." .. self._fieldNames[i + 1] .. " = " .. val)
    		end
    	elseif self._fieldCount > 0 then
    		SimpleEmitter.AppendLine(self, "local self = setmetatable({")
    		SimpleEmitter.Indent(self)
    		for i = 0, self._fieldCount - 1 do
    			local val: string = self._fieldDefaults[i + 1]
    			if val == nil then
    				val = SimpleEmitter.DefaultForType(self, self._fieldTypes[i + 1])
    			end
    			SimpleEmitter.AppendLine(self, self._fieldNames[i + 1] .. " = " .. val .. ",")
    		end
    		SimpleEmitter.Dedent(self)
    		SimpleEmitter.AppendLine(self, "} :: " .. className .. "_self, " .. className .. ")")
    	else
    		SimpleEmitter.AppendLine(self, "local self = setmetatable({} :: " .. className .. "_self, " .. className .. ")")
    	end
    	SimpleEmitter.AppendLine(self, "return self")
    	SimpleEmitter.Dedent(self)
    	SimpleEmitter.AppendLine(self, "end")
    end

    function SimpleEmitter.EmitConstructor(self: SimpleEmitter, className: string, ctor: ConstructorDeclarationSyntax): ()
    	local parms: string = ""
    	for i = 0, #ctor.Parameters - 1 do
    		if i > 0 then
    			parms = parms .. ", "
    		end
    		parms = parms .. ctor.Parameters[i + 1].Name .. ": " .. SimpleEmitter.MapType(self, ctor.Parameters[i + 1].TypeName)
    	end
    	SimpleEmitter.AppendLine(self, "function " .. className .. ".new(" .. parms .. "): " .. className)
    	SimpleEmitter.Indent(self)
    	local savedParamCount: number = self._paramCount
    	local savedLocalCount: number = self._localCount
    	self._paramCount = 0
    	self._localCount = 0
    	for i = 0, #ctor.Parameters - 1 do
    		self._paramNames[self._paramCount + 1] = ctor.Parameters[i + 1].Name
    		self._paramTypes[self._paramCount + 1] = ctor.Parameters[i + 1].TypeName
    		self._paramCount = self._paramCount + 1
    	end
    	if self._baseClassName ~= nil and ctor.BaseOrThisKeyword == "base" then
    		local baseArgs: string = ""
    		if ctor.InitializerArguments ~= nil then
    			for i = 0, #ctor.InitializerArguments - 1 do
    				if i > 0 then
    					baseArgs = baseArgs .. ", "
    				end
    				baseArgs = baseArgs .. SimpleEmitter.EmitExpression(self, ctor.InitializerArguments[i + 1])
    			end
    		end
    		SimpleEmitter.AppendLine(self, "local self = setmetatable(" .. self._baseClassName .. ".new(" .. baseArgs .. ") :: any, " .. className .. ")")
    		for i = 0, self._fieldCount - 1 do
    			local val: string = self._fieldDefaults[i + 1]
    			if val == nil then
    				val = SimpleEmitter.DefaultForType(self, self._fieldTypes[i + 1])
    			end
    			SimpleEmitter.AppendLine(self, "self." .. self._fieldNames[i + 1] .. " = " .. val)
    		end
    	elseif self._baseClassName ~= nil then
    		SimpleEmitter.AppendLine(self, "local self = setmetatable(" .. self._baseClassName .. ".new() :: any, " .. className .. ")")
    		for i = 0, self._fieldCount - 1 do
    			local val: string = self._fieldDefaults[i + 1]
    			if val == nil then
    				val = SimpleEmitter.DefaultForType(self, self._fieldTypes[i + 1])
    			end
    			SimpleEmitter.AppendLine(self, "self." .. self._fieldNames[i + 1] .. " = " .. val)
    		end
    	elseif self._fieldCount > 0 then
    		SimpleEmitter.AppendLine(self, "local self = setmetatable({")
    		SimpleEmitter.Indent(self)
    		for i = 0, self._fieldCount - 1 do
    			local val: string = self._fieldDefaults[i + 1]
    			if val == nil then
    				val = SimpleEmitter.DefaultForType(self, self._fieldTypes[i + 1])
    			end
    			SimpleEmitter.AppendLine(self, self._fieldNames[i + 1] .. " = " .. val .. ",")
    		end
    		SimpleEmitter.Dedent(self)
    		SimpleEmitter.AppendLine(self, "} :: " .. className .. "_self, " .. className .. ")")
    	else
    		SimpleEmitter.AppendLine(self, "local self = setmetatable({} :: " .. className .. "_self, " .. className .. ")")
    	end
    	if ctor.Body ~= nil then
    		local savedStatic: boolean = self._isStaticContext
    		self._isStaticContext = false
    		SimpleEmitter.EmitStatements(self, ctor.Body.Statements)
    		self._isStaticContext = savedStatic
    	end
    	SimpleEmitter.AppendLine(self, "return self")
    	self._paramCount = savedParamCount
    	self._localCount = savedLocalCount
    	SimpleEmitter.Dedent(self)
    	SimpleEmitter.AppendLine(self, "end")
    end

    function SimpleEmitter.EmitMethod(self: SimpleEmitter, className: string, method: MethodDeclarationSyntax, isAllStatic: boolean): ()
    	local retType: string = SimpleEmitter.MapType(self, method.ReturnType)
    	local parms: string = ""
    	if not method.IsStatic and not isAllStatic then
    		parms = "self: " .. className
    	end
    	for i = 0, #method.Parameters - 1 do
    		if #parms > 0 then
    			parms = parms .. ", "
    		end
    		parms = parms .. method.Parameters[i + 1].Name .. ": " .. SimpleEmitter.MapType(self, method.Parameters[i + 1].TypeName)
    	end
    	SimpleEmitter.AppendLine(self, "function " .. className .. "." .. method.Name .. "(" .. parms .. "): " .. retType)
    	SimpleEmitter.Indent(self)
    	local savedParamCount: number = self._paramCount
    	local savedLocalCount: number = self._localCount
    	self._paramCount = 0
    	self._localCount = 0
    	for i = 0, #method.Parameters - 1 do
    		self._paramNames[self._paramCount + 1] = method.Parameters[i + 1].Name
    		self._paramTypes[self._paramCount + 1] = method.Parameters[i + 1].TypeName
    		self._paramCount = self._paramCount + 1
    	end
    	local savedStatic: boolean = self._isStaticContext
    	self._isStaticContext = method.IsStatic or isAllStatic
    	if method.Body ~= nil then
    		SimpleEmitter.EmitStatements(self, method.Body.Statements)
    	end
    	self._isStaticContext = savedStatic
    	self._paramCount = savedParamCount
    	self._localCount = savedLocalCount
    	SimpleEmitter.Dedent(self)
    	SimpleEmitter.AppendLine(self, "end")
    end

    function SimpleEmitter.EmitExpressionProperty(self: SimpleEmitter, className: string, prop: PropertyDeclarationSyntax, isAllStatic: boolean): ()
    	local retType: string = SimpleEmitter.MapType(self, prop.TypeName)
    	local parms: string = ""
    	if not prop.IsStatic and not isAllStatic then
    		parms = "self: " .. className
    	end
    	SimpleEmitter.AppendLine(self, "function " .. className .. ".get_" .. prop.Name .. "(" .. parms .. "): " .. retType)
    	SimpleEmitter.Indent(self)
    	local savedStatic: boolean = self._isStaticContext
    	self._isStaticContext = prop.IsStatic or isAllStatic
    	local expr: string = SimpleEmitter.EmitExpression(self, prop.ExpressionBody)
    	SimpleEmitter.AppendLine(self, "return " .. expr)
    	self._isStaticContext = savedStatic
    	SimpleEmitter.Dedent(self)
    	SimpleEmitter.AppendLine(self, "end")
    end

    function SimpleEmitter.VisitEnumDeclaration(self: SimpleEmitter, node: EnumDeclarationSyntax): ()
    	local name: string = node.Name
    	local isNumeric: boolean = false
    	for i = 0, #node.Members - 1 do
    		local em: EnumMemberSyntax = node.Members[i + 1]
    		if em.Value ~= nil then
    			isNumeric = true
    		end
    	end
    	SimpleEmitter.AppendLine(self, "local " .. name .. " = table.freeze({")
    	SimpleEmitter.Indent(self)
    	local autoValue: number = 0
    	for i = 0, #node.Members - 1 do
    		local em: EnumMemberSyntax = node.Members[i + 1]
    		local memberName: string = em.Name
    		if em.Value ~= nil then
    			local val: string = SimpleEmitter.EmitExpression(self, em.Value)
    			SimpleEmitter.AppendLine(self, memberName .. " = " .. val .. ",")
    		elseif isNumeric then
    			SimpleEmitter.AppendLine(self, memberName .. " = " .. SimpleEmitter.IntToString(self, autoValue) .. ",")
    			autoValue += 1
    		else
    			SimpleEmitter.AppendLine(self, memberName .. " = \"" .. memberName .. "\",")
    		end
    	end
    	SimpleEmitter.Dedent(self)
    	SimpleEmitter.AppendLine(self, "})")
    	if isNumeric then
    		SimpleEmitter.AppendLine(self, "export type " .. name .. " = number")
    	else
    		SimpleEmitter.AppendLine(self, "export type " .. name .. " = keyof<typeof(" .. name .. ")>")
    	end
    	SimpleEmitter.AppendLine(self, "")
    end

    function SimpleEmitter.EmitStatements(self: SimpleEmitter, stmts: { StatementSyntax }): ()
    	for i = 0, #stmts - 1 do
    		SimpleEmitter.EmitStatement(self, stmts[i + 1])
    	end
    end

    function SimpleEmitter.EmitStatement(self: SimpleEmitter, stmt: StatementSyntax): ()
    	if stmt == nil then
    		return
    	end
    	local kind: number = stmt.Kind
    	if kind == 8792 then
    		local block: BlockSyntax = stmt
    		SimpleEmitter.EmitStatements(self, block.Statements)
    		return
    	end
    	if kind == 8805 then
    		local ret: ReturnStatementSyntax = stmt
    		if ret.Expression == nil then
    			SimpleEmitter.AppendLine(self, "return")
    		else
    			SimpleEmitter.AppendLine(self, "return " .. SimpleEmitter.EmitExpression(self, ret.Expression))
    		end
    		return
    	end
    	if kind == 8797 then
    		local exprStmt: ExpressionStatementSyntax = stmt
    		local exprText: string = SimpleEmitter.EmitExpressionStatement(self, exprStmt.Expression)
    		SimpleEmitter.AppendLine(self, exprText)
    		return
    	end
    	if kind == 8793 then
    		local localDecl: LocalDeclarationStatementSyntax = stmt
    		local varName: string = SimpleEmitter.EscapeId(localDecl.VariableName)
    		local luauType: string = SimpleEmitter.MapType(self, localDecl.TypeName)
    		if self._localCount < 64 then
    			self._localNames[self._localCount + 1] = varName
    			self._localTypes[self._localCount + 1] = localDecl.TypeName
    			self._localCount = self._localCount + 1
    		end
    		if localDecl.Initializer ~= nil then
    			local init: string = SimpleEmitter.EmitExpression(self, localDecl.Initializer)
    			SimpleEmitter.AppendLine(self, "local " .. varName .. ": " .. luauType .. " = " .. init)
    		else
    			SimpleEmitter.AppendLine(self, "local " .. varName .. ": " .. luauType .. " = " .. SimpleEmitter.DefaultForType(self, localDecl.TypeName))
    		end
    		return
    	end
    	if kind == 8802 then
    		local ws: WhileStatementSyntax = stmt
    		SimpleEmitter.AppendLine(self, "while " .. SimpleEmitter.EmitExpression(self, ws.Condition) .. " do")
    		SimpleEmitter.Indent(self)
    		SimpleEmitter.EmitBlockBody(self, ws.Body)
    		SimpleEmitter.Dedent(self)
    		SimpleEmitter.AppendLine(self, "end")
    		return
    	end
    	if kind == 8811 then
    		local fs: ForStatementSyntax = stmt
    		SimpleEmitter.EmitForStatement(self, fs)
    		return
    	end
    	if kind == 8812 then
    		local fes: ForEachStatementSyntax = stmt
    		if self._localCount < 64 then
    			self._localNames[self._localCount + 1] = fes.Identifier
    			self._localTypes[self._localCount + 1] = fes.TypeName
    			self._localCount = self._localCount + 1
    		end
    		SimpleEmitter.AppendLine(self, "for _, " .. fes.Identifier .. " in " .. SimpleEmitter.EmitExpression(self, fes.Expression) .. " do")
    		SimpleEmitter.Indent(self)
    		SimpleEmitter.EmitBlockBody(self, fes.Body)
    		SimpleEmitter.Dedent(self)
    		SimpleEmitter.AppendLine(self, "end")
    		return
    	end
    	if kind == 8810 then
    		local ds: DoStatementSyntax = stmt
    		SimpleEmitter.AppendLine(self, "repeat")
    		SimpleEmitter.Indent(self)
    		SimpleEmitter.EmitBlockBody(self, ds.Body)
    		SimpleEmitter.Dedent(self)
    		SimpleEmitter.AppendLine(self, "until not (" .. SimpleEmitter.EmitExpression(self, ds.Condition) .. ")")
    		return
    	end
    	if kind == 8821 then
    		local ss: SwitchStatementSyntax = stmt
    		SimpleEmitter.EmitSwitchStatement(self, ss)
    		return
    	end
    	if kind == 8825 then
    		local ts: TryStatementSyntax = stmt
    		SimpleEmitter.EmitTryStatement(self, ts)
    		return
    	end
    	if kind == 8808 then
    		local thr: ThrowStatementSyntax = stmt
    		if thr.Expression ~= nil then
    			if thr.Expression.Kind == 8649 then
    				local obj: ObjectCreationExpressionSyntax = thr.Expression
    				if #obj.Arguments > 0 then
    					SimpleEmitter.AppendLine(self, "error(" .. SimpleEmitter.EmitExpression(self, obj.Arguments[1]) .. ")")
    				else
    					SimpleEmitter.AppendLine(self, "error(\"" .. obj.TypeName .. "\")")
    				end
    			else
    				SimpleEmitter.AppendLine(self, "error(" .. SimpleEmitter.EmitExpression(self, thr.Expression) .. ")")
    			end
    		else
    			SimpleEmitter.AppendLine(self, "error(\"re-throw\")")
    		end
    		return
    	end
    	if kind == 8818 then
    		local lockStmt: LockStatementSyntax = stmt
    		SimpleEmitter.AppendLine(self, "-- lock (" .. SimpleEmitter.EmitExpression(self, lockStmt.Expression) .. ")")
    		SimpleEmitter.EmitStatements(self, lockStmt.Block.Statements)
    		return
    	end
    	if kind == 8813 then
    		local usingStmt: UsingStatementSyntax = stmt
    		if usingStmt.Declaration ~= nil then
    			local varName: string = usingStmt.Declaration.VariableName
    			local init: string = if usingStmt.Declaration.Initializer ~= nil then SimpleEmitter.EmitExpression(self, usingStmt.Declaration.Initializer) else "nil"
    			SimpleEmitter.AppendLine(self, "local " .. varName .. " = " .. init)
    		end
    		SimpleEmitter.AppendLine(self, "do")
    		self._indent += 1
    		SimpleEmitter.EmitStatements(self, usingStmt.Block.Statements)
    		self._indent -= 1
    		SimpleEmitter.AppendLine(self, "end")
    		return
    	end
    	if kind == 9081 then
    		local tuple: TupleDeconstructionStatementSyntax = stmt
    		local names: string = ""
    		for i = 0, #tuple.VariableNames - 1 do
    			if i > 0 then
    				names = names .. ", "
    			end
    			names = names .. tuple.VariableNames[i + 1]
    		end
    		local init: string = SimpleEmitter.EmitExpression(self, tuple.Initializer)
    		SimpleEmitter.AppendLine(self, "local " .. names .. " = " .. init)
    		return
    	end
    	stmt:AcceptWalker(self)
    end

    function SimpleEmitter.VisitIfStatement(self: SimpleEmitter, node: IfStatementSyntax): ()
    	SimpleEmitter.AppendLine(self, "if " .. SimpleEmitter.EmitExpression(self, node.Condition) .. " then")
    	SimpleEmitter.Indent(self)
    	SimpleEmitter.EmitBlockBody(self, node.ThenBody)
    	SimpleEmitter.Dedent(self)
    	if node.ElseBody ~= nil then
    		SimpleEmitter.EmitElseBody(self, node.ElseBody)
    	else
    		SimpleEmitter.AppendLine(self, "end")
    	end
    end

    function SimpleEmitter.EmitElseBody(self: SimpleEmitter, elseBody: StatementSyntax): ()
    	if elseBody == nil then
    		SimpleEmitter.AppendLine(self, "end")
    		return
    	end
    	if elseBody.Kind == 8792 then
    		SimpleEmitter.AppendLine(self, "else")
    		SimpleEmitter.Indent(self)
    		local block: BlockSyntax = elseBody
    		SimpleEmitter.EmitStatements(self, block.Statements)
    		SimpleEmitter.Dedent(self)
    		SimpleEmitter.AppendLine(self, "end")
    		return
    	end
    	if elseBody.Kind == 8819 then
    		local elseIf: IfStatementSyntax = elseBody
    		SimpleEmitter.AppendLine(self, "elseif " .. SimpleEmitter.EmitExpression(self, elseIf.Condition) .. " then")
    		SimpleEmitter.Indent(self)
    		SimpleEmitter.EmitBlockBody(self, elseIf.ThenBody)
    		SimpleEmitter.Dedent(self)
    		if elseIf.ElseBody ~= nil then
    			SimpleEmitter.EmitElseBody(self, elseIf.ElseBody)
    		else
    			SimpleEmitter.AppendLine(self, "end")
    		end
    		return
    	end
    	SimpleEmitter.AppendLine(self, "else")
    	SimpleEmitter.Indent(self)
    	SimpleEmitter.EmitStatement(self, elseBody)
    	SimpleEmitter.Dedent(self)
    	SimpleEmitter.AppendLine(self, "end")
    end

    function SimpleEmitter.VisitBreakStatement(self: SimpleEmitter, node: BreakStatementSyntax): ()
    	SimpleEmitter.AppendLine(self, "break")
    end

    function SimpleEmitter.VisitContinueStatement(self: SimpleEmitter, node: ContinueStatementSyntax): ()
    	SimpleEmitter.AppendLine(self, "continue")
    end

    function SimpleEmitter.EmitBlockBody(self: SimpleEmitter, body: StatementSyntax): ()
    	if body == nil then
    		return
    	end
    	if body.Kind == 8792 then
    		local block: BlockSyntax = body
    		SimpleEmitter.EmitStatements(self, block.Statements)
    	else
    		SimpleEmitter.EmitStatement(self, body)
    	end
    end

    function SimpleEmitter.EmitForStatement(self: SimpleEmitter, fs: ForStatementSyntax): ()
    	local isSimpleNumericFor: boolean = false
    	local varName: string = ""
    	local startVal: string = ""
    	local endExpr: string = ""
    	if fs.Declaration ~= nil and fs.Declaration.Kind == 8793 and fs.Condition ~= nil and #fs.Incrementors == 1 then
    		local decl: LocalDeclarationStatementSyntax = fs.Declaration
    		varName = decl.VariableName
    		if decl.Initializer ~= nil then
    			startVal = SimpleEmitter.EmitExpression(self, decl.Initializer)
    		end
    		local condKind: number = fs.Condition.Kind
    		if condKind >= 8668 and condKind <= 8688 then
    			local cond: BinaryExpressionSyntax = fs.Condition
    			local inc: ExpressionSyntax = fs.Incrementors[1]
    			local incIsPlus: boolean = false
    			if inc.Kind == 8738 or inc.Kind == 8739 then
    				local post: PostfixUnaryExpressionSyntax = inc
    				if post.OperatorKind == 8263 then
    					incIsPlus = true
    				end
    			elseif inc.Kind == 8734 then
    				incIsPlus = true
    			end
    			if incIsPlus then
    				if cond.OperatorToken.Text == "<" then
    					endExpr = SimpleEmitter.EmitExpression(self, cond.Right) .. " - 1"
    					isSimpleNumericFor = true
    				elseif cond.OperatorToken.Text == "<=" then
    					endExpr = SimpleEmitter.EmitExpression(self, cond.Right)
    					isSimpleNumericFor = true
    				end
    			end
    		end
    	end
    	if isSimpleNumericFor then
    		SimpleEmitter.AppendLine(self, "for " .. varName .. " = " .. startVal .. ", " .. endExpr .. " do")
    		SimpleEmitter.Indent(self)
    		SimpleEmitter.EmitBlockBody(self, fs.Body)
    		SimpleEmitter.Dedent(self)
    		SimpleEmitter.AppendLine(self, "end")
    	else
    		if fs.Declaration ~= nil then
    			SimpleEmitter.EmitStatement(self, fs.Declaration)
    		end
    		local condText: string = "true"
    		if fs.Condition ~= nil then
    			condText = SimpleEmitter.EmitExpression(self, fs.Condition)
    		end
    		SimpleEmitter.AppendLine(self, "while " .. condText .. " do")
    		SimpleEmitter.Indent(self)
    		SimpleEmitter.EmitBlockBody(self, fs.Body)
    		for i = 0, #fs.Incrementors - 1 do
    			SimpleEmitter.AppendLine(self, SimpleEmitter.EmitExpressionStatement(self, fs.Incrementors[i + 1]))
    		end
    		SimpleEmitter.Dedent(self)
    		SimpleEmitter.AppendLine(self, "end")
    	end
    end

    function SimpleEmitter.EmitSwitchStatement(self: SimpleEmitter, ss: SwitchStatementSyntax): ()
    	local switchExpr: string = SimpleEmitter.EmitExpression(self, ss.Expression)
    	local switchVar: string = "__switch_val"
    	SimpleEmitter.AppendLine(self, "local " .. switchVar .. " = " .. switchExpr)
    	local isFirst: boolean = true
    	for i = 0, #ss.Sections - 1 do
    		local section: SwitchSectionSyntax = ss.Sections[i + 1]
    		local isDefault: boolean = false
    		local caseCondition: string = ""
    		for j = 0, #section.Labels - 1 do
    			if section.Labels[j + 1] == nil then
    				isDefault = true
    			else
    				local labelExpr: string = SimpleEmitter.EmitExpression(self, section.Labels[j + 1])
    				if #caseCondition > 0 then
    					caseCondition = caseCondition .. " or "
    				end
    				caseCondition = caseCondition .. switchVar .. " == " .. labelExpr
    			end
    		end
    		if isDefault and #caseCondition == 0 then
    			if isFirst then
    				SimpleEmitter.AppendLine(self, "do")
    			else
    				SimpleEmitter.AppendLine(self, "else")
    			end
    		elseif isFirst then
    			SimpleEmitter.AppendLine(self, "if " .. caseCondition .. " then")
    		else
    			SimpleEmitter.AppendLine(self, "elseif " .. caseCondition .. " then")
    		end
    		SimpleEmitter.Indent(self)
    		for j = 0, #section.Statements - 1 do
    			local sj: StatementSyntax = section.Statements[j + 1]
    			local sjText: string = sj:Accept()
    			if sjText == "break;" then
    				continue
    			end
    			SimpleEmitter.EmitStatement(self, sj)
    		end
    		SimpleEmitter.Dedent(self)
    		isFirst = false
    	end
    	SimpleEmitter.AppendLine(self, "end")
    end

    function SimpleEmitter.EmitTryStatement(self: SimpleEmitter, ts: TryStatementSyntax): ()
    	local errVar: string = "__err"
    	if #ts.Catches > 0 and ts.Catches[1].Identifier ~= nil then
    		errVar = ts.Catches[1].Identifier
    	end
    	SimpleEmitter.AppendLine(self, "local __ok, " .. errVar .. " = pcall(function()")
    	SimpleEmitter.Indent(self)
    	if ts.Block ~= nil then
    		SimpleEmitter.EmitStatements(self, ts.Block.Statements)
    	end
    	SimpleEmitter.Dedent(self)
    	SimpleEmitter.AppendLine(self, "end)")
    	if #ts.Catches > 0 then
    		SimpleEmitter.AppendLine(self, "if not __ok then")
    		SimpleEmitter.Indent(self)
    		SimpleEmitter.EmitStatements(self, ts.Catches[1].Block.Statements)
    		SimpleEmitter.Dedent(self)
    		SimpleEmitter.AppendLine(self, "end")
    	end
    	if ts.FinallyBlock ~= nil then
    		SimpleEmitter.EmitStatements(self, ts.FinallyBlock.Statements)
    	end
    end

    function SimpleEmitter.EmitExpressionStatement(self: SimpleEmitter, expr: ExpressionSyntax): string
    	if expr == nil then
    		return ""
    	end
    	local kind: number = expr.Kind
    	if kind == 8714 then
    		local assign: AssignmentExpressionSyntax = expr
    		return SimpleEmitter.EmitExpression(self, assign.Left) .. " = " .. SimpleEmitter.EmitExpression(self, assign.Right)
    	end
    	if kind == 8715 then
    		local assign: AssignmentExpressionSyntax = expr
    		return SimpleEmitter.EmitExpression(self, assign.Left) .. " += " .. SimpleEmitter.EmitExpression(self, assign.Right)
    	end
    	if kind == 8716 then
    		local assign: AssignmentExpressionSyntax = expr
    		return SimpleEmitter.EmitExpression(self, assign.Left) .. " -= " .. SimpleEmitter.EmitExpression(self, assign.Right)
    	end
    	if kind == 8717 then
    		local assign: AssignmentExpressionSyntax = expr
    		return SimpleEmitter.EmitExpression(self, assign.Left) .. " *= " .. SimpleEmitter.EmitExpression(self, assign.Right)
    	end
    	if kind == 8718 then
    		local assign: AssignmentExpressionSyntax = expr
    		return SimpleEmitter.EmitExpression(self, assign.Left) .. " /= " .. SimpleEmitter.EmitExpression(self, assign.Right)
    	end
    	if kind == 8719 then
    		local assign: AssignmentExpressionSyntax = expr
    		return SimpleEmitter.EmitExpression(self, assign.Left) .. " %= " .. SimpleEmitter.EmitExpression(self, assign.Right)
    	end
    	if kind == 8725 then
    		local assign: AssignmentExpressionSyntax = expr
    		local caLeft: string = SimpleEmitter.EmitExpression(self, assign.Left)
    		return "if " .. caLeft .. " == nil then " .. caLeft .. " = " .. SimpleEmitter.EmitExpression(self, assign.Right) .. " end"
    	end
    	if kind == 8738 then
    		local post: PostfixUnaryExpressionSyntax = expr
    		return SimpleEmitter.EmitExpression(self, post.Operand) .. " += 1"
    	end
    	if kind == 8739 then
    		local post: PostfixUnaryExpressionSyntax = expr
    		return SimpleEmitter.EmitExpression(self, post.Operand) .. " -= 1"
    	end
    	if kind == 8734 then
    		local pre: PrefixUnaryExpressionSyntax = expr
    		return SimpleEmitter.EmitExpression(self, pre.Operand) .. " += 1"
    	end
    	if kind == 8735 then
    		local pre: PrefixUnaryExpressionSyntax = expr
    		return SimpleEmitter.EmitExpression(self, pre.Operand) .. " -= 1"
    	end
    	return SimpleEmitter.EmitExpression(self, expr)
    end

    function SimpleEmitter.EmitExpression(self: SimpleEmitter, expr: ExpressionSyntax): string
    	if expr == nil then
    		return "nil"
    	end
    	local kind: number = expr.Kind
    	if kind == 8748 then
    		return "true"
    	end
    	if kind == 8749 then
    		return "false"
    	end
    	if kind == 8754 then
    		return "nil"
    	end
    	if kind == 8753 then
    		return "nil"
    	end
    	if kind == 8750 then
    		local lit: LiteralExpressionSyntax = expr
    		local text: string = lit.Token.Text
    		if #text > 0 then
    			local last: number = string.byte(text, #text - 1 + 1)
    			if last == string.byte("f", 1) or last == string.byte("F", 1) or last == string.byte("d", 1) or last == string.byte("D", 1) or last == string.byte("m", 1) or last == string.byte("M", 1) or last == string.byte("L", 1) or last == string.byte("l", 1) or last == string.byte("u", 1) or last == string.byte("U", 1) then
    				text = string.sub(text, 0 + 1, 0 + #text - 1)
    			end
    		end
    		return text
    	end
    	if kind == 8751 then
    		local lit: LiteralExpressionSyntax = expr
    		return lit.Token.Text
    	end
    	if kind == 8655 then
    		local lit: LiteralExpressionSyntax = expr
    		local raw: string = lit.Token.Text
    		if #raw >= 3 and string.byte(raw, 1) == string.byte("$", 1) and string.byte(raw, 2) == 34 then
    			local inner: string = string.sub(raw, 2 + 1, 2 + #raw - 3)
    			local result: string = ""
    			local ci: number = 0
    			while ci < #inner do
    				if ci + 1 < #inner and string.byte(inner, ci + 1) == string.byte("{", 1) and string.byte(inner, ci + 1 + 1) == string.byte("{", 1) then
    					result = result .. "\\{"
    					ci = ci + 2
    				elseif ci + 1 < #inner and string.byte(inner, ci + 1) == string.byte("}", 1) and string.byte(inner, ci + 1 + 1) == string.byte("}", 1) then
    					result = result .. "\\}"
    					ci = ci + 2
    				elseif string.byte(inner, ci + 1) == string.byte("{", 1) then
    					local depth: number = 1
    					local exprStart: number = ci + 1
    					ci = ci + 1
    					while ci < #inner and depth > 0 do
    						if string.byte(inner, ci + 1) == string.byte("{", 1) then
    							depth = depth + 1
    						elseif string.byte(inner, ci + 1) == string.byte("}", 1) then
    							depth = depth - 1
    						end
    						if depth > 0 then
    							ci = ci + 1
    						end
    					end
    					local csExpr: string = string.sub(inner, exprStart + 1, exprStart + ci - exprStart)
    					local colonPos: number = -1
    					local parenDepth: number = 0
    					for si = 0, #csExpr - 1 do
    						if string.byte(csExpr, si + 1) == string.byte("(", 1) then
    							parenDepth = parenDepth + 1
    						elseif string.byte(csExpr, si + 1) == string.byte(")", 1) then
    							parenDepth = parenDepth - 1
    						elseif string.byte(csExpr, si + 1) == string.byte(":", 1) and parenDepth == 0 then
    							colonPos = si
    							break
    						end
    					end
    					if colonPos >= 0 then
    						csExpr = string.sub(csExpr, 0 + 1, 0 + colonPos)
    					end
    					local luauExpr: string = SimpleEmitter.TransformInterpolationExpr(self, csExpr)
    					result = result .. "{" .. luauExpr .. "}"
    					if ci < #inner then
    						ci = ci + 1
    					end
    				elseif string.byte(inner, ci + 1) == 92 then
    					if ci + 1 < #inner then
    						local esc: number = string.byte(inner, ci + 1 + 1)
    						if esc == string.byte("n", 1) then
    							result = result .. "\\n"
    							ci = ci + 2
    						elseif esc == string.byte("t", 1) then
    							result = result .. "\\t"
    							ci = ci + 2
    						elseif esc == string.byte("r", 1) then
    							result = result .. "\\r"
    							ci = ci + 2
    						elseif esc == 92 then
    							result = result .. "\\\\"
    							ci = ci + 2
    						elseif esc == 34 then
    							result = result .. "\""
    							ci = ci + 2
    						else
    							result = result .. string.byte(inner, ci + 1)
    							ci = ci + 1
    						end
    					else
    						result = result .. string.byte(inner, ci + 1)
    						ci = ci + 1
    					end
    				else
    					result = result .. string.byte(inner, ci + 1)
    					ci = ci + 1
    				end
    			end
    			return "`" .. result .. "`"
    		end
    		return raw
    	end
    	if kind == 8752 then
    		local lit: LiteralExpressionSyntax = expr
    		local charText: string = lit.Token.Text
    		if #charText >= 3 and string.byte(charText, 1) == 39 and string.byte(charText, #charText - 1 + 1) == 39 then
    			local inner: string = string.sub(charText, 1 + 1, 1 + #charText - 2)
    			if inner == "\\n" then
    				return "10"
    			end
    			if inner == "\\r" then
    				return "13"
    			end
    			if inner == "\\t" then
    				return "9"
    			end
    			if inner == "\\\\" then
    				return "92"
    			end
    			if inner == "\\'" then
    				return "39"
    			end
    			if inner == "\\\"" then
    				return "34"
    			end
    			if inner == "\\0" then
    				return "0"
    			end
    			if inner == "\"" then
    				return "34"
    			end
    			if #inner == 6 and string.byte(inner, 1) == 92 and string.byte(inner, 2) == string.byte("u", 1) then
    				local hex: string = string.sub(inner, 2 + 1, 2 + 4)
    				local val: number = 0
    				for ci = 0, 4 - 1 do
    					val = val * 16 + SyntaxFacts.HexValue(string.byte(hex, ci + 1))
    				end
    				return tostring(val)
    			end
    			if #inner == 1 then
    				return "string.byte(\"" .. inner .. "\", 1)"
    			end
    		end
    		return "string.byte(" .. charText .. ", 1)"
    	end
    	if kind == 8616 then
    		local ident: IdentifierNameSyntax = expr
    		local name: string = ident.Identifier.Text
    		if name == "null" then
    			return "nil"
    		end
    		if name == "true" then
    			return "true"
    		end
    		if name == "false" then
    			return "false"
    		end
    		if name == "this" then
    			return "self"
    		end
    		local escaped: string = SimpleEmitter.EscapeId(name)
    		if not self._isStaticContext and #self._currentClassName > 0 then
    			for i = 0, self._fieldCount - 1 do
    				if self._fieldNames[i + 1] == name then
    					return "self." .. name
    				end
    			end
    		end
    		return escaped
    	end
    	if kind == 8632 then
    		local paren: ParenthesizedExpressionSyntax = expr
    		return "(" .. SimpleEmitter.EmitExpression(self, paren.Expression) .. ")"
    	end
    	if kind >= 8668 and kind <= 8688 then
    		return SimpleEmitter.EmitBinary(self, expr)
    	end
    	if kind == 8657 then
    		local bin: BinaryExpressionSyntax = expr
    		local isLeft: string = SimpleEmitter.EmitExpression(self, bin.Left)
    		local isType: string = SimpleEmitter.EmitExpression(self, bin.Right)
    		if isType == "string" then
    			return "(type(" .. isLeft .. ") == \"string\")"
    		end
    		if isType == "number" or isType == "int" or isType == "float" or isType == "double" then
    			return "(type(" .. isLeft .. ") == \"number\")"
    		end
    		if isType == "boolean" or isType == "bool" then
    			return "(type(" .. isLeft .. ") == \"boolean\")"
    		end
    		if isType == "nil" or isType == "null" then
    			return "(" .. isLeft .. " == nil)"
    		end
    		return "(" .. isLeft .. " ~= nil)"
    	end
    	if kind == 8692 then
    		local isPat: IsPatternExpressionSyntax = expr
    		local isLeft: string = SimpleEmitter.EmitExpression(self, isPat.Expression)
    		local isType: string = isPat.TypeName
    		local luauType: string = SimpleEmitter.MapType(self, isType)
    		local varName: string = isPat.Designation
    		if self._localCount < 64 then
    			self._localNames[self._localCount + 1] = varName
    			self._localTypes[self._localCount + 1] = isType
    			self._localCount = self._localCount + 1
    		end
    		SimpleEmitter.AppendLine(self, "local " .. varName .. ": " .. luauType .. " = " .. isLeft)
    		if luauType == "string" then
    			return "type(" .. varName .. ") == \"string\""
    		end
    		if luauType == "number" then
    			return "type(" .. varName .. ") == \"number\""
    		end
    		if luauType == "boolean" then
    			return "type(" .. varName .. ") == \"boolean\""
    		end
    		return varName .. " ~= nil"
    	end
    	if kind == 8658 then
    		local bin: BinaryExpressionSyntax = expr
    		return SimpleEmitter.EmitExpression(self, bin.Left)
    	end
    	if kind == 8691 then
    		local ca: ConditionalAccessExpressionSyntax = expr
    		local caObj: string = SimpleEmitter.EmitExpression(self, ca.Expression)
    		local caFull: string = SimpleEmitter.EmitExpression(self, ca.WhenNotNull)
    		return "(if " .. caObj .. " ~= nil then " .. caFull .. " else nil)"
    	end
    	if kind == 8730 or kind == 8731 or kind == 8733 then
    		local pre: PrefixUnaryExpressionSyntax = expr
    		local opText: string = pre.OperatorToken.Text
    		if opText == "!" then
    			return "not " .. SimpleEmitter.EmitExpression(self, pre.Operand)
    		end
    		if opText == "-" then
    			return "-" .. SimpleEmitter.EmitExpression(self, pre.Operand)
    		end
    		return opText .. SimpleEmitter.EmitExpression(self, pre.Operand)
    	end
    	if kind == 8734 then
    		local pre: PrefixUnaryExpressionSyntax = expr
    		return SimpleEmitter.EmitExpression(self, pre.Operand) .. " + 1"
    	end
    	if kind == 8735 then
    		local pre: PrefixUnaryExpressionSyntax = expr
    		return SimpleEmitter.EmitExpression(self, pre.Operand) .. " - 1"
    	end
    	if kind == 8740 then
    		local pre: PrefixUnaryExpressionSyntax = expr
    		local inner: string = SimpleEmitter.EmitExpression(self, pre.Operand)
    		if #inner > 11 and string.sub(inner, 0 + 1, 0 + 11) == "Task.Delay(" then
    			local delayArg: string = string.sub(inner, 11 + 1, 11 + #inner - 12)
    			return "task.wait(" .. delayArg .. " / 1000)"
    		end
    		if #inner > 11 and string.sub(inner, 0 + 1, 0 + 11) == "task.Delay(" then
    			local delayArg: string = string.sub(inner, 11 + 1, 11 + #inner - 12)
    			return "task.wait(" .. delayArg .. " / 1000)"
    		end
    		if inner == "Task.Yield()" or inner == "task.Yield()" then
    			return "task.wait()"
    		end
    		return inner
    	end
    	if kind == 8738 or kind == 8739 then
    		local post: PostfixUnaryExpressionSyntax = expr
    		return SimpleEmitter.EmitExpression(self, post.Operand)
    	end
    	if kind >= 8714 and kind <= 8726 then
    		return SimpleEmitter.EmitAssignment(self, expr)
    	end
    	if kind == 8689 then
    		return SimpleEmitter.EmitMemberAccess(self, expr)
    	end
    	if kind == 8634 then
    		return SimpleEmitter.EmitInvocation(self, expr)
    	end
    	if kind == 8649 then
    		return SimpleEmitter.EmitObjectCreation(self, expr)
    	end
    	if kind == 8651 then
    		return SimpleEmitter.EmitArrayCreation(self, expr)
    	end
    	if kind == 8635 then
    		return SimpleEmitter.EmitElementAccess(self, expr)
    	end
    	if kind == 8640 then
    		local cast: CastExpressionSyntax = expr
    		return SimpleEmitter.EmitExpression(self, cast.Expression)
    	end
    	if kind == 8643 then
    		return SimpleEmitter.EmitLambda(self, expr)
    	end
    	if kind == 8633 then
    		local cond: ConditionalExpressionSyntax = expr
    		return "if " .. SimpleEmitter.EmitExpression(self, cond.Condition) .. " then " .. SimpleEmitter.EmitExpression(self, cond.WhenTrue) .. " else " .. SimpleEmitter.EmitExpression(self, cond.WhenFalse)
    	end
    	if kind == 9023 then
    		return SimpleEmitter.EmitSwitchExpression(self, expr)
    	end
    	return "nil --[[unknown expr kind " .. SimpleEmitter.IntToString(self, kind) .. "]]"
    end

    function SimpleEmitter.EmitBinary(self: SimpleEmitter, expr: ExpressionSyntax): string
    	local bin: BinaryExpressionSyntax = expr
    	local left: string = SimpleEmitter.EmitExpression(self, bin.Left)
    	local right: string = SimpleEmitter.EmitExpression(self, bin.Right)
    	local op: string = bin.OperatorToken.Text
    	if op == "!=" then
    		return left .. " ~= " .. right
    	end
    	if op == "&&" then
    		return left .. " and " .. right
    	end
    	if op == "||" then
    		return left .. " or " .. right
    	end
    	if op == "??" then
    		return "if " .. left .. " ~= nil then " .. left .. " else " .. right
    	end
    	if op == "+" then
    		local isStringConcat: boolean = false
    		if bin.Left.Kind == 8751 then
    			isStringConcat = true
    		end
    		if bin.Right.Kind == 8751 then
    			isStringConcat = true
    		end
    		if SimpleEmitter.ContainsConcatOp(self, left) then
    			isStringConcat = true
    		end
    		if SimpleEmitter.ContainsConcatOp(self, right) then
    			isStringConcat = true
    		end
    		if bin.Left.Kind >= 8668 and bin.Left.Kind <= 8688 then
    			if SimpleEmitter.HasStringLiteralInChain(self, bin.Left) then
    				isStringConcat = true
    			end
    		end
    		if bin.Right.Kind >= 8668 and bin.Right.Kind <= 8688 then
    			if SimpleEmitter.HasStringLiteralInChain(self, bin.Right) then
    				isStringConcat = true
    			end
    		end
    		if not isStringConcat and SimpleEmitter.HasStringTypedOperand(self, bin.Left) then
    			isStringConcat = true
    		end
    		if not isStringConcat and SimpleEmitter.HasStringTypedOperand(self, bin.Right) then
    			isStringConcat = true
    		end
    		if isStringConcat then
    			local lVal: string = SimpleEmitter.WrapCharForConcat(self, bin.Left, left)
    			local rVal: string = SimpleEmitter.WrapCharForConcat(self, bin.Right, right)
    			return lVal .. " .. " .. rVal
    		end
    	end
    	if op == "/" then
    		if SimpleEmitter.IsIntegerExpression(self, bin.Left) and SimpleEmitter.IsIntegerExpression(self, bin.Right) then
    			return left .. " // " .. right
    		end
    	end
    	if op == "&" then
    		return "bit32.band(" .. left .. ", " .. right .. ")"
    	end
    	if op == "|" then
    		return "bit32.bor(" .. left .. ", " .. right .. ")"
    	end
    	if op == "^" then
    		return "bit32.bxor(" .. left .. ", " .. right .. ")"
    	end
    	if op == "<<" then
    		return "bit32.lshift(" .. left .. ", " .. right .. ")"
    	end
    	if op == ">>" then
    		return "bit32.rshift(" .. left .. ", " .. right .. ")"
    	end
    	return left .. " " .. op .. " " .. right
    end

    function SimpleEmitter.HasStringLiteralInChain(self: SimpleEmitter, expr: ExpressionSyntax): boolean
    	if expr.Kind == 8751 then
    		return true
    	end
    	if expr.Kind >= 8668 and expr.Kind <= 8688 then
    		local bin: BinaryExpressionSyntax = expr
    		if bin.OperatorToken.Text == "+" then
    			if SimpleEmitter.HasStringLiteralInChain(self, bin.Left) then
    				return true
    			end
    			if SimpleEmitter.HasStringLiteralInChain(self, bin.Right) then
    				return true
    			end
    		end
    	end
    	return false
    end

    function SimpleEmitter.ContainsConcatOp(self: SimpleEmitter, emitted: string): boolean
    	local idx: number = 0
    	while idx <= #emitted - 4 do
    		if string.byte(emitted, idx + 1) == string.byte(" ", 1) and string.byte(emitted, idx + 1 + 1) == string.byte(".", 1) and string.byte(emitted, idx + 2 + 1) == string.byte(".", 1) and string.byte(emitted, idx + 3 + 1) == string.byte(" ", 1) then
    			return true
    		end
    		idx += 1
    	end
    	return false
    end

    function SimpleEmitter.HasStringTypedOperand(self: SimpleEmitter, expr: ExpressionSyntax): boolean
    	if expr.Kind == 8616 then
    		local id: IdentifierNameSyntax = expr
    		local name: string = id.Identifier.Text
    		local varType: string = SimpleEmitter.GetVariableType(self, name)
    		if varType ~= nil then
    			return SimpleEmitter.IsStringType(self, varType)
    		end
    		if not self._isStaticContext then
    			local fieldType: string = SimpleEmitter.GetFieldType(self, name)
    			if fieldType ~= nil then
    				return SimpleEmitter.IsStringType(self, fieldType)
    			end
    		end
    	end
    	return false
    end

    function SimpleEmitter.IsIntegerType(self: SimpleEmitter, typeName: string): boolean
    	if typeName == nil then
    		return false
    	end
    	if typeName == "int" then
    		return true
    	end
    	if typeName == "long" then
    		return true
    	end
    	if typeName == "short" then
    		return true
    	end
    	if typeName == "byte" then
    		return true
    	end
    	if typeName == "sbyte" then
    		return true
    	end
    	if typeName == "ushort" then
    		return true
    	end
    	if typeName == "uint" then
    		return true
    	end
    	if typeName == "ulong" then
    		return true
    	end
    	if typeName == "char" then
    		return true
    	end
    	return false
    end

    function SimpleEmitter.IsIntegerExpression(self: SimpleEmitter, expr: ExpressionSyntax): boolean
    	if expr.Kind == 8750 then
    		return true
    	end
    	if expr.Kind == 8616 then
    		local id: IdentifierNameSyntax = expr
    		local name: string = id.Identifier.Text
    		local varType: string = SimpleEmitter.GetVariableType(self, name)
    		if varType ~= nil then
    			return SimpleEmitter.IsIntegerType(self, varType)
    		end
    		if not self._isStaticContext then
    			local fieldType: string = SimpleEmitter.GetFieldType(self, name)
    			if fieldType ~= nil then
    				return SimpleEmitter.IsIntegerType(self, fieldType)
    			end
    		end
    	end
    	if expr.Kind >= 8668 and expr.Kind <= 8688 then
    		local bin: BinaryExpressionSyntax = expr
    		local op: string = bin.OperatorToken.Text
    		if op == "+" or op == "-" or op == "*" or op == "/" or op == "%" then
    			return SimpleEmitter.IsIntegerExpression(self, bin.Left) and SimpleEmitter.IsIntegerExpression(self, bin.Right)
    		end
    	end
    	return false
    end

    function SimpleEmitter.IsCharTypedExpression(self: SimpleEmitter, expr: ExpressionSyntax): boolean
    	if expr.Kind == 8616 then
    		local id: IdentifierNameSyntax = expr
    		local name: string = id.Identifier.Text
    		local varType: string = SimpleEmitter.GetVariableType(self, name)
    		if varType == "char" then
    			return true
    		end
    	end
    	return false
    end

    function SimpleEmitter.WrapCharForConcat(self: SimpleEmitter, expr: ExpressionSyntax, emitted: string): string
    	if expr.Kind == 8752 then
    		return "string.char(" .. emitted .. ")"
    	end
    	if SimpleEmitter.IsCharTypedExpression(self, expr) then
    		return "string.char(" .. emitted .. ")"
    	end
    	if expr.Kind == 8640 then
    		local cast: CastExpressionSyntax = expr
    		if cast.TypeName == "char" then
    			return "string.char(" .. emitted .. ")"
    		end
    	end
    	return emitted
    end

    function SimpleEmitter.EmitAssignment(self: SimpleEmitter, expr: ExpressionSyntax): string
    	local assign: AssignmentExpressionSyntax = expr
    	local left: string = SimpleEmitter.EmitExpression(self, assign.Left)
    	local right: string = SimpleEmitter.EmitExpression(self, assign.Right)
    	local kind: number = expr.Kind
    	if kind == 8714 then
    		return left .. " = " .. right
    	end
    	if kind == 8715 then
    		if assign.Right.Kind == 8751 then
    			return left .. " ..= " .. right
    		end
    		if assign.Right.Kind >= 8668 and assign.Right.Kind <= 8688 then
    			if SimpleEmitter.HasStringLiteralInChain(self, assign.Right) then
    				return left .. " ..= " .. right
    			end
    		end
    		if SimpleEmitter.ContainsConcatOp(self, right) then
    			return left .. " ..= " .. right
    		end
    		return left .. " += " .. right
    	end
    	if kind == 8716 then
    		return left .. " -= " .. right
    	end
    	if kind == 8717 then
    		return left .. " *= " .. right
    	end
    	if kind == 8718 then
    		return left .. " /= " .. right
    	end
    	if kind == 8719 then
    		return left .. " %= " .. right
    	end
    	if kind == 8725 then
    		return "if " .. left .. " == nil then " .. left .. " = " .. right .. " end"
    	end
    	return left .. " = " .. right
    end

    function SimpleEmitter.EmitMemberAccess(self: SimpleEmitter, expr: ExpressionSyntax): string
    	local ma: MemberAccessExpressionSyntax = expr
    	local memberName: string = ma.Name.Text
    	local obj: string = SimpleEmitter.EmitExpression(self, ma.Expression)
    	if memberName == "Length" or memberName == "Count" then
    		local countVarType: string = SimpleEmitter.GetVariableType(self, SimpleEmitter.GetIdentifierName(self, ma.Expression))
    		if countVarType ~= nil and #countVarType > 11 and string.sub(countVarType, 0 + 1, 0 + 11) == "Dictionary<" then
    			self._needsRuntime = true
    			return "__rt.dictCount(" .. obj .. ")"
    		end
    		if countVarType ~= nil and #countVarType > 8 and string.sub(countVarType, 0 + 1, 0 + 8) == "HashSet<" then
    			self._needsRuntime = true
    			return "__rt.dictCount(" .. obj .. ")"
    		end
    		return "#" .. obj
    	end
    	if obj == "Console" and memberName == "WriteLine" then
    		return "print"
    	end
    	if obj == "Console" and memberName == "Write" then
    		return "print"
    	end
    	if obj == "Math" then
    		local luauMath: string = SimpleEmitter.MapMathMember(self, memberName)
    		if luauMath ~= nil then
    			return luauMath
    		end
    	end
    	if obj == "string" and memberName == "Empty" then
    		return "\"\""
    	end
    	if obj == "int" and memberName == "MaxValue" then
    		return "2147483647"
    	end
    	if obj == "int" and memberName == "MinValue" then
    		return "-2147483648"
    	end
    	if obj == "double" and memberName == "MaxValue" then
    		return "math.huge"
    	end
    	if obj == "double" and memberName == "MinValue" then
    		return "-math.huge"
    	end
    	if obj == "double" and memberName == "NaN" then
    		return "0/0"
    	end
    	if obj == "double" and memberName == "PositiveInfinity" then
    		return "math.huge"
    	end
    	if obj == "double" and memberName == "NegativeInfinity" then
    		return "-math.huge"
    	end
    	if obj == "double" and memberName == "Epsilon" then
    		return "2.2204460492503131e-16"
    	end
    	if obj == "float" and memberName == "MaxValue" then
    		return "math.huge"
    	end
    	if obj == "float" and memberName == "MinValue" then
    		return "-math.huge"
    	end
    	if obj == "float" and memberName == "NaN" then
    		return "0/0"
    	end
    	if obj == "float" and memberName == "PositiveInfinity" then
    		return "math.huge"
    	end
    	if obj == "float" and memberName == "NegativeInfinity" then
    		return "-math.huge"
    	end
    	if memberName == "Keys" then
    		local varType: string = SimpleEmitter.GetVariableType(self, SimpleEmitter.GetIdentifierName(self, ma.Expression))
    		if varType ~= nil and #varType > 11 and string.sub(varType, 0 + 1, 0 + 11) == "Dictionary<" then
    			self._needsRuntime = true
    			return "__rt.keys(" .. obj .. ")"
    		end
    	end
    	if memberName == "Values" then
    		local varType: string = SimpleEmitter.GetVariableType(self, SimpleEmitter.GetIdentifierName(self, ma.Expression))
    		if varType ~= nil and #varType > 11 and string.sub(varType, 0 + 1, 0 + 11) == "Dictionary<" then
    			self._needsRuntime = true
    			return "__rt.values(" .. obj .. ")"
    		end
    	end
    	if memberName == "ElapsedMilliseconds" then
    		local swType: string = SimpleEmitter.GetVariableType(self, SimpleEmitter.GetIdentifierName(self, ma.Expression))
    		if swType ~= nil and swType == "Stopwatch" then
    			self._needsRuntime = true
    			return "__rt.Stopwatch.GetElapsedMilliseconds(" .. obj .. ")"
    		end
    	end
    	if memberName == "Elapsed" then
    		local swType: string = SimpleEmitter.GetVariableType(self, SimpleEmitter.GetIdentifierName(self, ma.Expression))
    		if swType ~= nil and swType == "Stopwatch" then
    			self._needsRuntime = true
    			return "__rt.Stopwatch.GetElapsedSeconds(" .. obj .. ")"
    		end
    	end
    	if obj == "Environment" and memberName == "NewLine" then
    		return "\"\\n\""
    	end
    	if obj == "DateTime" and memberName == "Now" then
    		return "os.time()"
    	end
    	if obj == "DateTime" and memberName == "UtcNow" then
    		return "os.time()"
    	end
    	if obj == "DateTime" and memberName == "MinValue" then
    		return "0"
    	end
    	if obj == "DateTime" and memberName == "MaxValue" then
    		return "253402300799"
    	end
    	if memberName == "TotalSeconds" then
    		local tsType: string = SimpleEmitter.GetVariableType(self, SimpleEmitter.GetIdentifierName(self, ma.Expression))
    		if tsType ~= nil and tsType == "TimeSpan" then
    			return obj
    		end
    	end
    	if memberName == "TotalMilliseconds" then
    		local tsType: string = SimpleEmitter.GetVariableType(self, SimpleEmitter.GetIdentifierName(self, ma.Expression))
    		if tsType ~= nil and tsType == "TimeSpan" then
    			return "(" .. obj .. " * 1000)"
    		end
    	end
    	if memberName == "TotalMinutes" then
    		local tsType: string = SimpleEmitter.GetVariableType(self, SimpleEmitter.GetIdentifierName(self, ma.Expression))
    		if tsType ~= nil and tsType == "TimeSpan" then
    			return "(" .. obj .. " / 60)"
    		end
    	end
    	if memberName == "TotalHours" then
    		local tsType: string = SimpleEmitter.GetVariableType(self, SimpleEmitter.GetIdentifierName(self, ma.Expression))
    		if tsType ~= nil and tsType == "TimeSpan" then
    			return "(" .. obj .. " / 3600)"
    		end
    	end
    	if obj == "TimeSpan" and memberName == "Zero" then
    		return "0"
    	end
    	if obj == "TimeSpan" and memberName == "MaxValue" then
    		return "math.huge"
    	end
    	if memberName == "HasValue" then
    		return "(" .. obj .. " ~= nil)"
    	end
    	if obj == "this" or obj == "self" then
    		return "self." .. memberName
    	end
    	if obj == "base" then
    		if self._baseClassName ~= nil then
    			return self._baseClassName .. "." .. memberName
    		end
    		return self._currentClassName .. "." .. memberName
    	end
    	return obj .. "." .. memberName
    end

    function SimpleEmitter.MapMathMember(self: SimpleEmitter, member: string): string
    	if member == "Max" then
    		return "math.max"
    	end
    	if member == "Min" then
    		return "math.min"
    	end
    	if member == "Abs" then
    		return "math.abs"
    	end
    	if member == "Floor" then
    		return "math.floor"
    	end
    	if member == "Ceiling" then
    		return "math.ceil"
    	end
    	if member == "Round" then
    		return "math.round"
    	end
    	if member == "Sqrt" then
    		return "math.sqrt"
    	end
    	if member == "Pow" then
    		return "math.pow"
    	end
    	if member == "Log" then
    		return "math.log"
    	end
    	if member == "PI" then
    		return "math.pi"
    	end
    	if member == "E" then
    		return "math.exp(1)"
    	end
    	if member == "Tau" then
    		return "(math.pi * 2)"
    	end
    	if member == "Sin" then
    		return "math.sin"
    	end
    	if member == "Cos" then
    		return "math.cos"
    	end
    	if member == "Tan" then
    		return "math.tan"
    	end
    	if member == "Asin" then
    		return "math.asin"
    	end
    	if member == "Acos" then
    		return "math.acos"
    	end
    	if member == "Atan" then
    		return "math.atan"
    	end
    	if member == "Atan2" then
    		return "math.atan2"
    	end
    	if member == "Sinh" then
    		return "math.sinh"
    	end
    	if member == "Cosh" then
    		return "math.cosh"
    	end
    	if member == "Tanh" then
    		return "math.tanh"
    	end
    	if member == "Exp" then
    		return "math.exp"
    	end
    	if member == "Sign" then
    		return "math.sign"
    	end
    	if member == "Clamp" then
    		return "math.clamp"
    	end
    	if member == "Truncate" then
    		return "math.modf"
    	end
    	return nil
    end

    function SimpleEmitter.IsInstanceMethod(self: SimpleEmitter, name: string): boolean
    	for i = 0, self._methodCount - 1 do
    		if self._methodNames[i + 1] == name and not self._isMethodStatic[i + 1] then
    			return true
    		end
    	end
    	return false
    end

    function SimpleEmitter.IsStaticMethod(self: SimpleEmitter, name: string): boolean
    	for i = 0, self._methodCount - 1 do
    		if self._methodNames[i + 1] == name and self._isMethodStatic[i + 1] then
    			return true
    		end
    	end
    	return false
    end

    function SimpleEmitter.IsKnownVariable(self: SimpleEmitter, name: string): boolean
    	for i = 0, self._paramCount - 1 do
    		if self._paramNames[i + 1] == name then
    			return true
    		end
    	end
    	for i = 0, self._localCount - 1 do
    		if self._localNames[i + 1] == name then
    			return true
    		end
    	end
    	return false
    end

    function SimpleEmitter.IsInstanceCallTarget(self: SimpleEmitter, target: ExpressionSyntax, emittedObj: string): boolean
    	if emittedObj == "self" then
    		return true
    	end
    	if #emittedObj > 5 and string.sub(emittedObj, 0 + 1, 0 + 5) == "self." then
    		return true
    	end
    	if target.Kind == 8690 then
    		return true
    	end
    	if target.Kind == 8616 then
    		local id: IdentifierNameSyntax = target
    		if SimpleEmitter.IsKnownVariable(self, id.Identifier.Text) then
    			return true
    		end
    	end
    	if target.Kind == 8689 then
    		local inner: MemberAccessExpressionSyntax = target
    		if inner.Expression.Kind == 8616 then
    			local leftId: IdentifierNameSyntax = inner.Expression
    			if SimpleEmitter.IsKnownVariable(self, leftId.Identifier.Text) then
    				return true
    			end
    		end
    		if inner.Expression.Kind == 8616 then
    			local leftId2: IdentifierNameSyntax = inner.Expression
    			if leftId2.Identifier.Text == "self" or leftId2.Identifier.Text == "this" then
    				return true
    			end
    		end
    	end
    	return false
    end

    function SimpleEmitter.EmitInvocation(self: SimpleEmitter, expr: ExpressionSyntax): string
    	local inv: InvocationExpressionSyntax = expr
    	local args: string = ""
    	for i = 0, #inv.Arguments - 1 do
    		if i > 0 then
    			args = args .. ", "
    		end
    		args = args .. SimpleEmitter.EmitExpression(self, inv.Arguments[i + 1])
    	end
    	if inv.Expression.Kind == 8689 then
    		local ma: MemberAccessExpressionSyntax = inv.Expression
    		local methodName: string = ma.Name.Text
    		local obj: string = SimpleEmitter.EmitExpression(self, ma.Expression)
    		if obj == "Console" and (methodName == "WriteLine" or methodName == "Write") then
    			return "print(" .. args .. ")"
    		end
    		if obj == "Math" then
    			if methodName == "Log10" and #inv.Arguments == 1 then
    				return "math.log(" .. args .. ", 10)"
    			end
    			if methodName == "Log2" and #inv.Arguments == 1 then
    				return "math.log(" .. args .. ", 2)"
    			end
    			if methodName == "Log" and #inv.Arguments == 2 then
    				local logX: string = SimpleEmitter.EmitExpression(self, inv.Arguments[1])
    				local logBase: string = SimpleEmitter.EmitExpression(self, inv.Arguments[2])
    				return "math.log(" .. logX .. ", " .. logBase .. ")"
    			end
    			if methodName == "Round" and #inv.Arguments == 2 then
    				local roundX: string = SimpleEmitter.EmitExpression(self, inv.Arguments[1])
    				local roundDigits: string = SimpleEmitter.EmitExpression(self, inv.Arguments[2])
    				return "math.floor(" .. roundX .. " * 10 ^ " .. roundDigits .. " + 0.5) / 10 ^ " .. roundDigits
    			end
    			if methodName == "DivRem" and #inv.Arguments == 2 then
    				local divA: string = SimpleEmitter.EmitExpression(self, inv.Arguments[1])
    				local divB: string = SimpleEmitter.EmitExpression(self, inv.Arguments[2])
    				return "math.floor(" .. divA .. " / " .. divB .. "), " .. divA .. " % " .. divB
    			end
    			if methodName == "BigMul" and #inv.Arguments == 2 then
    				local mulA: string = SimpleEmitter.EmitExpression(self, inv.Arguments[1])
    				local mulB: string = SimpleEmitter.EmitExpression(self, inv.Arguments[2])
    				return mulA .. " * " .. mulB
    			end
    			if methodName == "ScaleB" and #inv.Arguments == 2 then
    				local sbX: string = SimpleEmitter.EmitExpression(self, inv.Arguments[1])
    				local sbN: string = SimpleEmitter.EmitExpression(self, inv.Arguments[2])
    				return sbX .. " * 2 ^ " .. sbN
    			end
    			if methodName == "FusedMultiplyAdd" and #inv.Arguments == 3 then
    				local fmaX: string = SimpleEmitter.EmitExpression(self, inv.Arguments[1])
    				local fmaY: string = SimpleEmitter.EmitExpression(self, inv.Arguments[2])
    				local fmaZ: string = SimpleEmitter.EmitExpression(self, inv.Arguments[3])
    				return fmaX .. " * " .. fmaY .. " + " .. fmaZ
    			end
    			if methodName == "CopySign" and #inv.Arguments == 2 then
    				local csX: string = SimpleEmitter.EmitExpression(self, inv.Arguments[1])
    				local csY: string = SimpleEmitter.EmitExpression(self, inv.Arguments[2])
    				return "math.abs(" .. csX .. ") * math.sign(" .. csY .. ")"
    			end
    			if methodName == "IEEERemainder" and #inv.Arguments == 2 then
    				local remX: string = SimpleEmitter.EmitExpression(self, inv.Arguments[1])
    				local remY: string = SimpleEmitter.EmitExpression(self, inv.Arguments[2])
    				return remX .. " - " .. remY .. " * math.round(" .. remX .. " / " .. remY .. ")"
