    		else
    			local patternExpr: string = SimpleEmitter.EmitExpression(self, arm.Pattern)
    			if #result == 0 then
    				result = "if " .. govExpr .. " == " .. patternExpr .. " then " .. armExpr
    			else
    				result = result .. " elseif " .. govExpr .. " == " .. patternExpr .. " then " .. armExpr
    			end
    		end
    	end
    	return result
    end

    function SimpleEmitter.IntToString(self: SimpleEmitter, value: number): string
    	if value == 0 then
    		return "0"
    	end
    	local negative: boolean = false
    	if value < 0 then
    		negative = true
    		value = -value
    	end
    	local result: string = ""
    	local n: number = value
    	while n > 0 do
    		local digit: number = n % 10
    		local c: number = (string.byte("0", 1) + digit)
    		result = string.char(c) .. result
    		n = n // 10
    	end
    	if negative then
    		result = "-" .. result
    	end
    	return result
    end


