    	end
    	if c >= string.byte("0", 1) and c <= string.byte("9", 1) then
    		return true
    	end
    	if c == string.byte("_", 1) then
    		return true
    	end
    	return false
    end

    function SimpleTranspiler.InsertRequires(self: SimpleTranspiler, emittedOutput: string, requireBlock: string): string
    	local sentinel: string = "-- Auto-generated by SimpleEmitter\n"
    	local sentinelLen: number = #sentinel
    	local sentinelIdx: number = SimpleTranspiler.IndexOf(self, emittedOutput, sentinel, 0)
    	if sentinelIdx == -1 then
    		return requireBlock .. emittedOutput
    	end
    	local insertionPoint: number = sentinelIdx + sentinelLen
    	if insertionPoint < #emittedOutput and string.byte(emittedOutput, insertionPoint + 1) == 10 then
    		insertionPoint += 1
    	end
    	local before: string = string.sub(emittedOutput, 0 + 1, 0 + insertionPoint)
    	local after: string = string.sub(emittedOutput, insertionPoint + 1)
    	return before .. requireBlock .. after
    end

    function SimpleTranspiler.BuildRequireBlock(self: SimpleTranspiler, modules: { string }, types: { string }, typeCounts: { number }, moduleCount: number): string
    	local result: string = ""
    	for m = 0, moduleCount - 1 do
    		local modName: string = modules[m + 1]
    		result = result .. "local _" .. modName .. "\n"
    		local typeSlotBase: number = m * 32
    		local typeCount: number = typeCounts[m + 1]
    		for t = 0, typeCount - 1 do
    			local typeName: string = types[typeSlotBase + t + 1]
    			result = result .. "local " .. typeName .. " = setmetatable({}, {__index = function(_, k)\n"
    			result = result .. "\tif not _" .. modName .. " then _" .. modName .. " = require(script.Parent." .. modName .. ") end\n"
    			result = result .. "\treturn _" .. modName .. "." .. typeName .. "[k]\n"
    			result = result .. "end})\n"
    		end
    	end
    	result = result .. "\n"
    	return result
    end

    function SimpleTranspiler.SortModuleSlots(self: SimpleTranspiler, modules: { string }, types: { string }, typeCounts: { number }, count: number): ()
    	for i = 1, count - 1 do
    		local keyModule: string = modules[i + 1]
    		local keyCount: number = typeCounts[i + 1]
    		local keyTypes: { string } = table.create(32)
    		local slotBase: number = i * 32
    		for t = 0, keyCount - 1 do
    			keyTypes[t + 1] = types[slotBase + t + 1]
    		end
    		local j: number = i - 1
    		while j >= 0 and SimpleTranspiler.StringGreaterThan(self, modules[j + 1], keyModule) do
    			modules[j + 1 + 1] = modules[j + 1]
    			typeCounts[j + 1 + 1] = typeCounts[j + 1]
    			local srcBase: number = j * 32
    			local dstBase: number = (j + 1) * 32
    			local srcCount: number = typeCounts[j + 1 + 1]
    			for t = 0, srcCount - 1 do
    				types[dstBase + t + 1] = types[srcBase + t + 1]
    			end
    			j -= 1
    		end
    		modules[j + 1 + 1] = keyModule
    		typeCounts[j + 1 + 1] = keyCount
    		local destBase: number = (j + 1) * 32
    		for t = 0, keyCount - 1 do
    			types[destBase + t + 1] = keyTypes[t + 1]
    		end
    	end
    end

    function SimpleTranspiler.SortTypeSlot(self: SimpleTranspiler, types: { string }, count: number, slotBase: number): ()
    	for i = 1, count - 1 do
    		local key: string = types[slotBase + i + 1]
    		local j: number = i - 1
    		while j >= 0 and SimpleTranspiler.StringGreaterThan(self, types[slotBase + j + 1], key) do
    			types[slotBase + j + 1 + 1] = types[slotBase + j + 1]
    			j -= 1
    		end
    		types[slotBase + j + 1 + 1] = key
    	end
    end

    function SimpleTranspiler.StringGreaterThan(self: SimpleTranspiler, a: string, b: string): boolean
    	local aLen: number = #a
    	local bLen: number = #b
    	local minLen: number = aLen
    	if bLen < minLen then
    		minLen = bLen
    	end
    	for i = 0, minLen - 1 do
    		if string.byte(a, i + 1) > string.byte(b, i + 1) then
    			return true
    		end
    		if string.byte(a, i + 1) < string.byte(b, i + 1) then
    			return false
    		end
    	end
    	return aLen > bLen
    end

    function SimpleTranspiler.IsIgnoredType(self: SimpleTranspiler, typeName: string): boolean
    	for i = 0, self._ignoredCount - 1 do
    		if self._ignoredTypes[i + 1] == typeName then
    			return true
    		end
    	end
    	return false
    end

    function SimpleTranspiler.StripDirectory(self: SimpleTranspiler, path: string): string
    	local lastSlash: number = -1
    	local i: number = #path - 1
    	while i >= 0 do
    		if string.byte(path, i + 1) == string.byte("/", 1) or string.byte(path, i + 1) == 92 then
    			lastSlash = i
    			break
    		end
    		i -= 1
    	end
    	if lastSlash == -1 then
    		return path
    	end
    	return string.sub(path, lastSlash + 1 + 1)
    end

    function SimpleTranspiler.StripExtension(self: SimpleTranspiler, name: string): string
    	local i: number = #name - 1
    	while i >= 0 do
    		if string.byte(name, i + 1) == string.byte(".", 1) then
    			return string.sub(name, 0 + 1, 0 + i)
    		end
    		i -= 1
    	end
    	return name
    end


    return { SimpleTranspiler = SimpleTranspiler }

end

