/// <summary>
/// Represents 'expr is Type varName' pattern expression (kind 8692).
/// </summary>
public class IsPatternExpressionSyntax : ExpressionSyntax
{
    public ExpressionSyntax Expression { get; }
    public string TypeName { get; }
