function SimpleEmitter.EmitObjectCreation(self: SimpleEmitter, expr: ExpressionSyntax): string
	local obj: ObjectCreationExpressionSyntax = expr
	local args: string = ""
	for i = 0, #obj.Arguments - 1 do
		if i > 0 then
			args = args .. ", "
		end
		args = args .. SimpleEmitter.EmitExpression(self, obj.Arguments[i + 1])
	end
	local typeName: string = obj.TypeName
	if typeName == "StringBuilder" then
		return "\"\""
	end
	if #typeName > 5 and string.sub(typeName, 0 + 1, 0 + 5) == "List<" then
		return "{}"
	end
	if #typeName > 11 and string.sub(typeName, 0 + 1, 0 + 11) == "Dictionary<" then
		return "{}"
	end
	if #typeName > 8 and string.sub(typeName, 0 + 1, 0 + 8) == "HashSet<" then
		return "{}"
	end
	if #typeName > 6 and string.sub(typeName, 0 + 1, 0 + 6) == "Queue<" then
		return "{}"
	end
	if #typeName > 6 and string.sub(typeName, 0 + 1, 0 + 6) == "Stack<" then
		return "{}"
	end
	if typeName == "Random" then
		if #obj.Arguments > 0 then
			return "Random.new(" .. args .. ")"
		end
		return "Random.new()"
	end
	if typeName == "Stopwatch" then
		self._needsRuntime = true
		return "__rt.Stopwatch.StartNew()"
	end
	if typeName == "CancellationTokenSource" then
		self._needsRuntime = true
		return "__rt.CancellationToken.new()"
	end
	if typeName == "Exception" or typeName == "InvalidOperationException" or typeName == "ArgumentException" or typeName == "ArgumentNullException" or typeName == "NotImplementedException" or typeName == "NotSupportedException" or typeName == "IndexOutOfRangeException" or typeName == "OverflowException" then
		if #obj.Arguments > 0 then
			return SimpleEmitter.EmitExpression(self, obj.Arguments[1])
		end
		return "\"" .. typeName .. "\""
	end
	if #obj.Initializers > 0 then
		local iife: string = "(function() local __obj = " .. typeName .. ".new(" .. args .. "); "
		for i = 0, #obj.Initializers - 1 do
			local fieldName: string = SimpleEmitter.EmitExpression(self, obj.Initializers[i + 1].Left)
			local fieldVal: string = SimpleEmitter.EmitExpression(self, obj.Initializers[i + 1].Right)
			iife = iife .. "__obj." .. fieldName .. " = " .. fieldVal .. "; "
		end
		iife = iife .. "return __obj end)()"
		return iife
	end
	if #typeName > 2 and string.sub(typeName, #typeName - 2 + 1) == "[]" then
		if #args == 0 then
			return "{}"
		end
		local elems: string = ""
		for i = 0, #obj.Arguments - 1 do
			if i > 0 then
				elems = elems .. ", "
			end
			elems = elems .. SimpleEmitter.EmitExpression(self, obj.Arguments[i + 1])
		end
		return "{ " .. elems .. " }"
	end
	return typeName .. ".new(" .. args .. ")"
end

function SimpleEmitter.EmitArrayCreation(self: SimpleEmitter, expr: ExpressionSyntax): string
