			return true
		end
		if string.byte(a, i + 1) < string.byte(b, i + 1) then
			return false
		end
	end
	return aLen > bLen
end

function SimpleTranspiler.IsIgnoredType(self: SimpleTranspiler, typeName: string): boolean
	for i = 0, self._ignoredCount - 1 do
		if self._ignoredTypes[i + 1] == typeName then
			return true
		end
	end
	return false
end

function SimpleTranspiler.StripDirectory(self: SimpleTranspiler, path: string): string
	local lastSlash: number = -1
	local i: number = #path - 1
	while i >= 0 do
		if string.byte(path, i + 1) == string.byte("/", 1) or string.byte(path, i + 1) == 92 then
			lastSlash = i
			break
		end
		i -= 1
	end
	if lastSlash == -1 then
		return path
	end
	return string.sub(path, lastSlash + 1 + 1)
end

function SimpleTranspiler.StripExtension(self: SimpleTranspiler, name: string): string
	local i: number = #name - 1
	while i >= 0 do
		if string.byte(name, i + 1) == string.byte(".", 1) then
			return string.sub(name, 0 + 1, 0 + i)
		end
		i -= 1
	end
	return name
end


return { SimpleTranspiler = SimpleTranspiler }
]]

local transpilerMod = customRequire({ _moduleName = "SimpleTranspiler" })
local SimpleTranspiler = transpilerMod.SimpleTranspiler

print("Creating SimpleTranspiler instance...")
local t = SimpleTranspiler.new()

print("PreScanning " .. fileCount .. " files...")
SimpleTranspiler.PreScan(t, csharpSources, csharpNames, fileCount)
print("TranspileAll...")
local results = SimpleTranspiler.TranspileAll(t, csharpSources, csharpNames, fileCount)
print("")

-- Compare each output with reference
local pass, fail = 0, 0
for i = 1, fileCount do
    local name = csharpNames[i]
    local luauOut = results[i]
    local ref = references[i]
    if luauOut == nil then
        fail = fail + 1
        print("  FAIL  " .. name .. " — nil output")
    else
        -- Trim trailing whitespace/newlines for comparison
        local function trim(s) while #s > 0 and (string.byte(s, #s) == 10 or string.byte(s, #s) == 13 or string.byte(s, #s) == 32) do s = string.sub(s, 1, #s - 1) end return s end
        local a = trim(luauOut)
        local b = trim(ref)
        if a == b then
            pass = pass + 1
            print("  MATCH " .. name)
        else
            fail = fail + 1
            -- Find first differing line
            local aLines, bLines = {}, {}
            for line in (a .. "\n"):gmatch("([^\n]*)\n") do table.insert(aLines, line) end
            for line in (b .. "\n"):gmatch("([^\n]*)\n") do table.insert(bLines, line) end
            local firstDiff = "?"
            for j = 1, math.max(#aLines, #bLines) do
                if aLines[j] ~= bLines[j] then
                    firstDiff = "line " .. j .. ":\n      Luau:  " .. tostring(aLines[j]):sub(1,80) .. "\n      C#ref: " .. tostring(bLines[j]):sub(1,80)
                    break
                end
            end
            print("  DIFF  " .. name .. " (" .. #aLines .. " vs " .. #bLines .. " lines) first: " .. firstDiff)
        end
    end
end

print("")
print(pass .. "/" .. (pass + fail) .. " files match")
if pass == fileCount then print("PERFECT MATCH — Luau transpiler produces identical output to C# transpiler!") end
